import React from 'react';
import { BrowserRouter, Routes, Route } from 'react-router-dom';
import Navbar from './components/Navbar';
import Dashboard from './pages/Dashboard';
import Products from './pages/Products';
import StockUpdates from './pages/StockUpdates';
import SalesRecords from './pages/SalesRecords';

export default function App() {
  return (
    <BrowserRouter>
      <Navbar />
      <Routes>
        <Route path='/' element={<Dashboard />} />
        <Route path='/products' element={<Products />} />
        <Route path='/stock-updates' element={<StockUpdates />} />
        <Route path='/sales-records' element={<SalesRecords />} />
      </Routes>
    </BrowserRouter>
  );
}

import React from 'react';
import { NavLink } from 'react-router-dom';

export default function Navbar() {
  const style = ({ isActive }) => ({
    textDecoration: 'none',
    color: isActive ? '#0f172a' : '#64748b',
    fontWeight: isActive ? 700 : 500
  });

  return (
    <nav style={{ borderBottom: '1px solid #e2e8f0', background: '#fff' }}>
      <div style={{ maxWidth: '1100px', margin: '0 auto', padding: '16px 24px', display: 'flex', justifyContent: 'space-between' }}>
        <h2 style={{ margin: 0 }}>ShopStock</h2>
        <div style={{ display: 'flex', gap: '18px' }}>
          <NavLink to='/' style={style}>Dashboard</NavLink>
          <NavLink to='/products' style={style}>Products</NavLink>
          <NavLink to='/stock-updates' style={style}>Stock Updates</NavLink>
          <NavLink to='/sales-records' style={style}>Sales Records</NavLink>
        </div>
      </div>
    </nav>
  );
}

import React from 'react';

export default function MetricCard({ label, value }) {
  return (
    <div style={{ border: '1px solid #e2e8f0', borderRadius: '14px', padding: '18px', background: '#fff' }}>
      <p style={{ margin: '0 0 8px 0', color: '#64748b' }}>{label}</p>
      <h3 style={{ margin: 0 }}>{value}</h3>
    </div>
  );
}

import React from 'react';
import MetricCard from '../components/MetricCard';

export default function Dashboard() {
  return (
    <div style={{ maxWidth: '1100px', margin: '0 auto', padding: '32px 24px' }}>
      <h1>Inventory Dashboard</h1>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(220px, 1fr))', gap: '18px', marginTop: '24px' }}>
        <MetricCard label='Total Products' value='54' />
        <MetricCard label='Low Stock Items' value='7' />
        <MetricCard label='Today Sales' value='$420' />
      </div>
    </div>
  );
}

import React from 'react';

const products = [
  { id: 1, name: 'Rice Pack', category: 'Groceries', price: 12, stock_quantity: 25 },
  { id: 2, name: 'Shampoo', category: 'Personal Care', price: 8, stock_quantity: 14 }
];

export default function Products() {
  return (
    <div style={{ maxWidth: '1100px', margin: '0 auto', padding: '32px 24px' }}>
      <h1>Products</h1>
      <div style={{ display: 'grid', gap: '14px' }}>
        {products.map(product => (
          <div key={product.id} style={{ border: '1px solid #e2e8f0', borderRadius: '12px', padding: '16px' }}>
            <strong>{product.name}</strong>
            <p style={{ margin: '6px 0', color: '#64748b' }}>{product.category}</p>
            <p style={{ margin: '6px 0' }}>Price: ${product.price}</p>
            <p style={{ margin: '6px 0' }}>Stock: {product.stock_quantity}</p>
          </div>
        ))}
      </div>
    </div>
  );
}

import React from 'react';

export default function StockUpdates() {
  return (
    <div style={{ maxWidth: '800px', margin: '0 auto', padding: '32px 24px' }}>
      <h1>Stock Updates</h1>
      <div style={{ border: '1px solid #e2e8f0', borderRadius: '14px', padding: '20px', display: 'grid', gap: '14px', background: '#fff' }}>
        <input placeholder='Product Name' style={{ padding: '12px', borderRadius: '10px', border: '1px solid #cbd5e1' }} />
        <input placeholder='Quantity Change' style={{ padding: '12px', borderRadius: '10px', border: '1px solid #cbd5e1' }} />
        <select style={{ padding: '12px', borderRadius: '10px', border: '1px solid #cbd5e1' }}>
          <option>Increase Stock</option>
          <option>Decrease Stock</option>
        </select>
        <button style={{ padding: '12px', borderRadius: '10px', border: 'none', background: '#0f172a', color: '#fff' }}>Save Update</button>
      </div>
    </div>
  );
}

import React from 'react';

const sales = [
  { id: 1, product_name: 'Rice Pack', quantity_sold: 3, total_amount: 36 },
  { id: 2, product_name: 'Shampoo', quantity_sold: 2, total_amount: 16 }
];

export default function SalesRecords() {
  return (
    <div style={{ maxWidth: '1100px', margin: '0 auto', padding: '32px 24px' }}>
      <h1>Sales Records</h1>
      <table style={{ width: '100%', borderCollapse: 'collapse', border: '1px solid #e2e8f0' }}>
        <thead style={{ background: '#f8fafc' }}>
          <tr>
            <th style={{ padding: '12px', textAlign: 'left' }}>Product</th>
            <th style={{ padding: '12px', textAlign: 'left' }}>Quantity</th>
            <th style={{ padding: '12px', textAlign: 'left' }}>Total</th>
          </tr>
        </thead>
        <tbody>
          {sales.map(item => (
            <tr key={item.id}>
              <td style={{ padding: '12px', borderTop: '1px solid #e2e8f0' }}>{item.product_name}</td>
              <td style={{ padding: '12px', borderTop: '1px solid #e2e8f0' }}>{item.quantity_sold}</td>
              <td style={{ padding: '12px', borderTop: '1px solid #e2e8f0' }}>${item.total_amount}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

from flask import Flask, jsonify

app = Flask(__name__)

@app.route('/api/products')
def get_products():
    return jsonify({
        'products': [
            {'id': 1, 'name': 'Rice Pack', 'category': 'Groceries', 'price': 12, 'stock_quantity': 25},
            {'id': 2, 'name': 'Shampoo', 'category': 'Personal Care', 'price': 8, 'stock_quantity': 14}
        ]
    })

@app.route('/api/sales')
def get_sales():
    return jsonify({
        'sales_records': [
            {'id': 1, 'product_name': 'Rice Pack', 'quantity_sold': 3, 'total_amount': 36},
            {'id': 2, 'product_name': 'Shampoo', 'quantity_sold': 2, 'total_amount': 16}
        ]
    })

if __name__ == '__main__':
    app.run(debug=True)
